import React, { useEffect, useState } from "react";

export default function DashboardCard({
  title,
  value,
  growth,
  icon
}) {
  const [displayValue, setDisplayValue] = useState(0);

  // Animate numbers smoothly
  useEffect(() => {
    if (typeof value !== "number") return;

    let start = 0;
    const duration = 800;
    const increment = value / (duration / 16);

    const counter = setInterval(() => {
      start += increment;
      if (start >= value) {
        start = value;
        clearInterval(counter);
      }
      setDisplayValue(Math.floor(start));
    }, 16);

    return () => clearInterval(counter);
  }, [value]);

  const isPositive = growth >= 0;

  return (
    <div className="relative bg-white/10 backdrop-blur-lg border border-yellow-400 p-6 rounded-2xl text-center text-white shadow-xl transition transform hover:scale-105 hover:shadow-2xl">

      {/* Optional Icon */}
      {icon && (
        <div className="text-2xl mb-2">
          {icon}
        </div>
      )}

      {/* Title */}
      <div className="text-sm text-white/70 tracking-wide uppercase">
        {title}
      </div>

      {/* Value */}
      <div className="text-4xl font-bold mt-2">
        {typeof value === "number" ? `₹ ${displayValue}` : value}
      </div>

      {/* Growth Indicator */}
      {growth !== undefined && (
        <div
          className={`mt-3 text-sm font-semibold ${
            isPositive ? "text-green-400" : "text-red-400"
          }`}
        >
          {isPositive ? "▲" : "▼"} {Math.abs(growth)}%
        </div>
      )}
    </div>
  );
}
